import type { ExecSyncOptions } from 'child_process'

import { execSync } from 'child_process'

import { warning } from './log.js'

export function tryInitRepoAndCommit(args: { cwd: string }): void {
  const execOpts: ExecSyncOptions = { cwd: args.cwd, stdio: 'ignore' }
  try {
    // Check if git is available
    execSync('git -v', execOpts)

    // Do nothing if already in a git repo
    if (isGitRepo(execOpts)) {
      return
    }

    // Initialize
    execSync('git init', execOpts)
    if (!ensureHasDefaultBranch(execOpts)) {
      execSync('git checkout -b main', execOpts)
    }

    // Add and commit files
    execSync('git add -A', execOpts)
    execSync('git commit -m "feat: initial commit"', execOpts)
  } catch (_) {
    warning('Failed to initialize git repository.')
  }
}

function isGitRepo(opts: ExecSyncOptions): boolean {
  try {
    execSync('git rev-parse --is-inside-work-tree', opts)
    return true
  } catch (_) {
    // Ignore errors
  }
  return false
}

function ensureHasDefaultBranch(opts: ExecSyncOptions): boolean {
  try {
    execSync(`git config init.defaultBranch`, opts)
    return true
  } catch (_) {
    // Ignore errros
  }
  return false
}

import validateNpmPackageName from 'validate-npm-package-name'

export interface ParsedWantedDependency {
  alias: string
  bareSpecifier: string
}

export type ParseWantedDependencyResult = Partial<ParsedWantedDependency> &
(
  Omit<ParsedWantedDependency, 'bareSpecifier'>
  | Omit<ParsedWantedDependency, 'alias'>
  | ParsedWantedDependency
)

export function parseWantedDependency (rawWantedDependency: string): ParseWantedDependencyResult {
  const versionDelimiter = rawWantedDependency.indexOf('@', 1) // starting from 1 to skip the @ that marks scope
  if (versionDelimiter !== -1) {
    const alias = rawWantedDependency.slice(0, versionDelimiter)
    if (validateNpmPackageName(alias).validForOldPackages) {
      return {
        alias,
        bareSpecifier: rawWantedDependency.slice(versionDelimiter + 1),
      }
    }
    return {
      bareSpecifier: rawWantedDependency,
    }
  }
  if (validateNpmPackageName(rawWantedDependency).validForOldPackages) {
    return {
      alias: rawWantedDependency,
    }
  }
  return {
    bareSpecifier: rawWantedDependency,
  }
}

import { BasicBuilder } from './BasicBuilder'
import { DocComment } from './DocComment'
import { TypeBuilder } from './TypeBuilder'
import { ValueBuilder } from './ValueBuilder'
import { Writer } from './Writer'

export class ConstDeclaration implements BasicBuilder {
  private docComment?: DocComment
  private value?: ValueBuilder

  constructor(
    readonly name: string,
    readonly type?: TypeBuilder,
  ) {}

  setDocComment(docComment: DocComment): this {
    this.docComment = docComment
    return this
  }

  setValue(value: ValueBuilder): this {
    this.value = value
    return this
  }

  write(writer: Writer): void {
    if (this.docComment) {
      writer.write(this.docComment)
    }
    writer.write('const ').write(this.name)
    if (this.type) {
      writer.write(': ').write(this.type)
    }
    if (this.value) {
      writer.write(' = ').write(this.value)
    }
  }
}

export function constDeclaration(name: string, type?: TypeBuilder) {
  return new ConstDeclaration(name, type)
}

import type { HasEffectsContext, InclusionContext } from '../../ExecutionContext';
import type { StatementNode } from './Node';

export function hasLoopBodyEffects(context: HasEffectsContext, body: StatementNode): boolean {
	const { brokenFlow, hasBreak, hasContinue, ignore } = context;
	const { breaks, continues } = ignore;
	ignore.breaks = true;
	ignore.continues = true;
	context.hasBreak = false;
	context.hasContinue = false;
	if (body.hasEffects(context)) return true;
	ignore.breaks = breaks;
	ignore.continues = continues;
	context.hasBreak = hasBreak;
	context.hasContinue = hasContinue;
	context.brokenFlow = brokenFlow;
	return false;
}

export function includeLoopBody(
	context: InclusionContext,
	body: StatementNode,
	includeChildrenRecursively: boolean | 'variables'
) {
	const { brokenFlow, hasBreak, hasContinue } = context;
	context.hasBreak = false;
	context.hasContinue = false;
	body.include(context, includeChildrenRecursively, { asSingleStatement: true });
	context.hasBreak = hasBreak;
	context.hasContinue = hasContinue;
	context.brokenFlow = brokenFlow;
}

import { type ElementWithTransition, vtcKey } from '../components/Transition'

// compiler should normalize class + :class bindings on the same element
// into a single binding ['staticClass', dynamic]
export function patchClass(
  el: Element,
  value: string | null,
  isSVG: boolean,
): void {
  // directly setting className should be faster than setAttribute in theory
  // if this is an element during a transition, take the temporary transition
  // classes into account.
  const transitionClasses = (el as ElementWithTransition)[vtcKey]
  if (transitionClasses) {
    value = (
      value ? [value, ...transitionClasses] : [...transitionClasses]
    ).join(' ')
  }
  if (value == null) {
    el.removeAttribute('class')
  } else if (isSVG) {
    el.setAttribute('class', value)
  } else {
    el.className = value
  }
}

