import { coerce, major } from 'semver';
import type {
  PackageCompatVersions,
  PackageVersionNames,
} from './backward-compatible-versions';
import { backwardCompatibleVersions } from './backward-compatible-versions';
import * as versions from './versions';
import { angularVersion } from './versions';

export function getPkgVersionForAngularMajorVersion(
  pkgVersionName: PackageVersionNames,
  angularMajorVersion: number
): string {
  return angularMajorVersion < major(coerce(angularVersion))
    ? (backwardCompatibleVersions[angularMajorVersion]?.[pkgVersionName] ??
        versions[pkgVersionName])
    : versions[pkgVersionName];
}

export function getPkgVersionsForAngularMajorVersion(
  angularMajorVersion: number
): PackageCompatVersions {
  return angularMajorVersion < major(coerce(angularVersion))
    ? (backwardCompatibleVersions[angularMajorVersion] ?? versions)
    : versions;
}

import type { Count, SanitizedCollectionConfig } from 'payload'

import toSnakeCase from 'to-snake-case'

import type { DrizzleAdapter } from './types.js'

import { buildQuery } from './queries/buildQuery.js'
import { getTransaction } from './utilities/getTransaction.js'

export const count: Count = async function count(
  this: DrizzleAdapter,
  { collection, locale, req, where: whereArg },
) {
  const collectionConfig: SanitizedCollectionConfig = this.payload.collections[collection].config

  const tableName = this.tableNameMap.get(toSnakeCase(collectionConfig.slug))

  const { joins, where } = buildQuery({
    adapter: this,
    fields: collectionConfig.flattenedFields,
    locale,
    tableName,
    where: whereArg,
  })

  const db = await getTransaction(this, req)

  const countResult = await this.countDistinct({
    db,
    joins,
    tableName,
    where,
  })

  return { totalDocs: countResult }
}

import type { Collection } from 'payload'

import { generatePayloadCookie, isolateObjectProperty, loginOperation } from 'payload'

import type { Context } from '../types.js'

export function login(collection: Collection): any {
  async function resolver(_, args, context: Context) {
    const options = {
      collection,
      data: {
        email: args.email,
        password: args.password,
        username: args.username,
      },
      depth: 0,
      req: isolateObjectProperty(context.req, 'transactionID'),
    }

    const result = await loginOperation(options)
    const cookie = generatePayloadCookie({
      collectionAuthConfig: collection.config.auth,
      cookiePrefix: context.req.payload.config.cookiePrefix,
      token: result.token,
    })

    context.headers['Set-Cookie'] = cookie

    if (collection.config.auth.removeTokenFromResponses) {
      delete result.token
    }

    return result
  }

  return resolver
}

import path from 'node:path'

import { writeSettings, type WriteSettingsOptions } from '@pnpm/config.writer'
import normalizePath from 'normalize-path'

export async function updatePatchedDependencies (
  patchedDependencies: Record<string, string>,
  opts: Omit<WriteSettingsOptions, 'updatedSettings'>
): Promise<void> {
  const workspaceDir = opts.workspaceDir ?? opts.rootProjectManifestDir
  for (const [patchName, patchPath] of Object.entries(patchedDependencies)) {
    if (path.isAbsolute(patchPath)) {
      patchedDependencies[patchName] = normalizePath(path.relative(workspaceDir, patchPath))
    }
  }
  await writeSettings({
    ...opts,
    workspaceDir,
    updatedSettings: {
      patchedDependencies: Object.keys(patchedDependencies).length ? patchedDependencies : undefined,
    },
  })
}

import type { BrowserCommandContext } from 'vitest/node'
import type { ScreenshotComparatorRegistry } from '../../../../../context'
import type { Comparator } from '../types'
import { pixelmatch } from './pixelmatch'

const comparators: {
  [ComparatorName in keyof ScreenshotComparatorRegistry]: Comparator<
    ScreenshotComparatorRegistry[ComparatorName]
  >
} = {
  pixelmatch,
}

export function getComparator<ComparatorName extends keyof ScreenshotComparatorRegistry>(
  comparator: ComparatorName,
  context: BrowserCommandContext,
): Comparator<ScreenshotComparatorRegistry[ComparatorName]> {
  if (comparator in comparators) {
    return comparators[comparator]
  }

  const customComparators = context
    .project
    .config
    .browser
    .expect
    ?.toMatchScreenshot
    ?.comparators

  if (customComparators && comparator in customComparators) {
    return customComparators[comparator]
  }

  throw new Error(`Unrecognized comparator ${comparator}`)
}

export type AnyComparator = Comparator<ScreenshotComparatorRegistry[keyof ScreenshotComparatorRegistry]>

import {CwdFS, PortablePath}   from '@yarnpkg/fslib';

import {Fetcher, FetchOptions} from './Fetcher';
import {WorkspaceResolver}     from './WorkspaceResolver';
import {Locator}               from './types';

export class WorkspaceFetcher implements Fetcher {
  supports(locator: Locator) {
    if (!locator.reference.startsWith(WorkspaceResolver.protocol))
      return false;

    return true;
  }

  getLocalPath(locator: Locator, opts: FetchOptions) {
    return this.getWorkspace(locator, opts).cwd;
  }

  async fetch(locator: Locator, opts: FetchOptions) {
    const sourcePath = this.getWorkspace(locator, opts).cwd;

    return {packageFs: new CwdFS(sourcePath), prefixPath: PortablePath.dot, localPath: sourcePath};
  }

  getWorkspace(locator: Locator, opts: FetchOptions) {
    return opts.project.getWorkspaceByCwd(locator.reference.slice(WorkspaceResolver.protocol.length) as PortablePath);
  }
}

