'use client';
import {
  type ChartAnyPluginSignature,
  type PolarChartSeriesType,
  useChartsRadialDataProviderProps,
} from '@mui/x-charts/internals';
import type { ChartsRadialDataProviderPremiumProps } from './ChartsRadialDataProviderPremium';
import type { RadialPremiumPluginSignatures } from './ChartsRadialDataProviderPremium.plugins';

export const useChartsRadialDataProviderPremiumProps = <
  SeriesType extends PolarChartSeriesType = PolarChartSeriesType,
  TSignatures extends readonly ChartAnyPluginSignature[] =
    RadialPremiumPluginSignatures<SeriesType>,
>(
  props: ChartsRadialDataProviderPremiumProps<SeriesType, TSignatures>,
) => {
  const { chartProviderProps, localeText, slots, slotProps, children } =
    useChartsRadialDataProviderProps(props);

  return {
    children,
    localeText,
    chartProviderProps,
    slots,
    slotProps,
  };
};

import { ErrorWithBatchIndex } from './ErrorWithBatchIndex'
import { setClassName } from './setClassName'

type UnknownErrorParams = {
  clientVersion: string
  batchRequestIdx?: number
}

export class PrismaClientUnknownRequestError extends Error implements ErrorWithBatchIndex {
  clientVersion: string
  batchRequestIdx?: number

  constructor(message: string, { clientVersion, batchRequestIdx }: UnknownErrorParams) {
    super(message)
    this.name = 'PrismaClientUnknownRequestError'

    this.clientVersion = clientVersion
    Object.defineProperty(this, 'batchRequestIdx', {
      value: batchRequestIdx,
      writable: true,
      enumerable: false,
    })
  }
  get [Symbol.toStringTag]() {
    return 'PrismaClientUnknownRequestError'
  }
}

setClassName(PrismaClientUnknownRequestError, 'PrismaClientUnknownRequestError')

import {
  createTemporaryReferenceSet,
  decodeAction,
  decodeFormState,
  decodeReply,
  loadServerAction,
  renderToReadableStream,
} from "@vitejs/plugin-rsc/rsc";
import { unstable_matchRSCServerRequest as matchRSCServerRequest } from "react-router";

import { routes } from "./routes";

export async function fetchServer(request: Request) {
  return await matchRSCServerRequest({
    createTemporaryReferenceSet,
    decodeAction,
    decodeFormState,
    decodeReply,
    loadServerAction,
    request,
    // @ts-expect-error
    routes,
    generateResponse(match, options) {
      return new Response(renderToReadableStream(match.payload, options), {
        status: match.statusCode,
        headers: match.headers,
      });
    },
  });
}

export default async function handler(request: Request) {
  const ssr = await import.meta.viteRsc.loadModule<
    typeof import("./entry.ssr")
  >("ssr", "index");
  return ssr.default(request, await fetchServer(request));
}

if (import.meta.hot) {
  import.meta.hot.accept();
}
